using System;
using System.Drawing;
using System.IO;
using System.Reflection;

namespace Hospital_System
{
    /// <summary>
    /// Provides the NeurAI application icon as an embedded resource,
    /// so it works regardless of whether NeurAI.ico exists on disk.
    /// </summary>
    internal static class AppIcon
    {
        private static Icon _icon;

        /// <summary>Returns the NeurAI icon, loading it once and caching it.</summary>
        public static Icon Get()
        {
            if (_icon != null) return _icon;
            try
            {
                // Try to load from embedded base64 first (always works)
                byte[] bytes = Convert.FromBase64String(GetBase64());
                using (var ms = new MemoryStream(bytes))
                    _icon = new Icon(ms);
            }
            catch
            {
                // Fall back to disk if somehow base64 decode fails
                try
                {
                    string path = Path.Combine(
                        Path.GetDirectoryName(Assembly.GetExecutingAssembly().Location),
                        "NeurAI.ico");
                    if (File.Exists(path))
                        _icon = new Icon(path);
                }
                catch { /* icon is non-critical */ }
            }
            return _icon;
        }

